output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?show ?showLabel WHERE {
  VALUES ?creator {
    wd:Q2150289 wd:Q6318075
  }
  .
  VALUES ?property {
    wdt:P170 wdt:P58 wdt:P86 wdt:P162
  }
  .
  ?show ?property ?creator .
  ?show wdt:P31 / wdt:P279 * wd:Q5398426 .
  FILTER(?show != wd:Q15659308)
  .
  ?show rdfs:label ?showLabel .
  FILTER(LANG(?showLabel) = 'en')
  .
}
